import React, { useState, useMemo } from 'react';

const theme = {
  bg: '#0f172a',
  surface: '#1e293b',
  card: '#334155',
  border: '#475569',
  text: '#f8fafc',
  muted: '#94a3b8',
  dim: '#64748b',
  blue: '#38bdf8',
  green: '#4ade80',
  orange: '#fb923c',
  purple: '#a78bfa',
};

const CORPORA = [
  {
    name: 'Simple',
    text: '<s> Jack I like </s> <s> Jack I do like </s>',
    defaultWord: 'Jack',
  },
  {
    name: 'Extended',
    text: '<s> I am Jack </s> <s> Jack I am </s> <s> Jack I like </s> <s> Jack I do like </s> <s> do I like Jack </s>',
    defaultWord: 'Jack',
  },
  {
    name: 'Animals',
    text: '<s> the cat sat </s> <s> the dog sat </s> <s> the cat ran </s>',
    defaultWord: 'cat',
  },
];

export default function App() {
  const [corpusIdx, setCorpusIdx] = useState(0);
  const [selectedWord, setSelectedWord] = useState(CORPORA[0].defaultWord);

  const corpus = CORPORA[corpusIdx];

  const tokens = useMemo(
    () => corpus.text.split(/\s+/).filter((t) => t.length > 0),
    [corpus]
  );

  const sentences = useMemo(() => {
    const sents = [];
    let current = [];
    tokens.forEach((t, i) => {
      current.push({ token: t, index: i });
      if (t === '</s>') {
        sents.push(current);
        current = [];
      }
    });
    if (current.length > 0) sents.push(current);
    return sents;
  }, [tokens]);

  const totalTokens = tokens.length;
  const wordCount = tokens.filter((t) => t === selectedWord).length;
  const probability = totalTokens > 0 ? wordCount / totalTokens : 0;
  const rounded = Math.round(probability * 10000) / 10000;

  const wordFreqs = useMemo(() => {
    const counts = {};
    tokens.forEach((t) => {
      counts[t] = (counts[t] || 0) + 1;
    });
    return Object.entries(counts).sort((a, b) => b[1] - a[1]);
  }, [tokens]);

  const maxCount = wordFreqs.length > 0 ? wordFreqs[0][1] : 1;

  const handleCorpusChange = (idx) => {
    setCorpusIdx(idx);
    setSelectedWord(CORPORA[idx].defaultWord);
  };

  const isSpecial = (t) => t === '<s>' || t === '</s>';

  return (
    <div
      style={{
        minHeight: '100vh',
        background: theme.bg,
        color: theme.text,
        fontFamily: "'Inter', system-ui, -apple-system, sans-serif",
        padding: '20px 16px',
        boxSizing: 'border-box',
      }}
    >
      <div style={{ maxWidth: 600, margin: '0 auto' }}>
        {/* Title */}
        <div style={{ marginBottom: 14 }}>
          <div
            style={{
              fontSize: 20,
              fontWeight: 700,
              color: theme.text,
              marginBottom: 4,
            }}
          >
            Unigram Probability
          </div>
          <div style={{ fontSize: 13, color: theme.dim }}>
            Click any word in the corpus to calculate its probability
          </div>
        </div>

        {/* Corpus selector */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
          {CORPORA.map((c, i) => (
            <button
              key={i}
              onClick={() => handleCorpusChange(i)}
              style={{
                padding: '6px 14px',
                borderRadius: 8,
                border: 'none',
                cursor: 'pointer',
                fontSize: 12,
                fontWeight: 600,
                background: i === corpusIdx ? theme.blue : theme.card,
                color: i === corpusIdx ? theme.bg : theme.muted,
                transition: 'all 0.2s',
              }}
            >
              {c.name}
            </button>
          ))}
        </div>

        {/* Corpus tokens */}
        <div
          style={{
            background: theme.surface,
            borderRadius: 12,
            padding: 14,
            marginBottom: 12,
            border: '1px solid ' + theme.border,
          }}
        >
          {sentences.map((sent, si) => (
            <div
              key={si}
              style={{
                display: 'flex',
                flexWrap: 'wrap',
                gap: 6,
                marginBottom: si < sentences.length - 1 ? 8 : 0,
              }}
            >
              {sent.map(({ token, index }) => {
                const isSel = token === selectedWord;
                const special = isSpecial(token);
                return (
                  <button
                    key={index}
                    onClick={() => setSelectedWord(token)}
                    style={{
                      padding: '5px 10px',
                      borderRadius: 6,
                      border: '2px solid ' + (isSel ? theme.blue : 'transparent'),
                      background: isSel ? theme.blue + '18' : 'transparent',
                      color: isSel
                        ? theme.blue
                        : special
                        ? theme.purple
                        : theme.text,
                      cursor: 'pointer',
                      fontSize: 14,
                      fontFamily: "'JetBrains Mono', monospace",
                      fontWeight: isSel ? 700 : special ? 500 : 400,
                      transition: 'all 0.2s',
                      transform: isSel ? 'scale(1.08)' : 'scale(1)',
                    }}
                  >
                    {token}
                  </button>
                );
              })}
            </div>
          ))}
          <div
            style={{
              marginTop: 10,
              paddingTop: 10,
              borderTop: '1px solid ' + theme.border,
              fontSize: 12,
              color: theme.dim,
              display: 'flex',
              justifyContent: 'space-between',
            }}
          >
            <span>
              Total tokens:{' '}
              <span style={{ color: theme.orange, fontWeight: 700 }}>
                {totalTokens}
              </span>
            </span>
            <span>
              Unique words:{' '}
              <span style={{ color: theme.muted, fontWeight: 600 }}>
                {wordFreqs.length}
              </span>
            </span>
          </div>
        </div>

        {/* Formula */}
        <div
          style={{
            background: theme.surface,
            borderRadius: 12,
            padding: 16,
            marginBottom: 12,
            border: '1px solid ' + theme.border,
            textAlign: 'center',
          }}
        >
          <div style={{ fontSize: 13, color: theme.dim, marginBottom: 14 }}>
            P(
            <span style={{ color: theme.blue, fontWeight: 600 }}>
              "{selectedWord}"
            </span>
            ) = Count(
            <span style={{ color: theme.blue }}>"{selectedWord}"</span>) / Total
            Tokens
          </div>

          <div
            style={{
              display: 'inline-flex',
              alignItems: 'center',
              gap: 16,
            }}
          >
            <div style={{ textAlign: 'center' }}>
              <div
                style={{
                  fontSize: 30,
                  fontWeight: 700,
                  color: theme.green,
                  fontFamily: "'JetBrains Mono', monospace",
                  transition: 'all 0.3s',
                }}
              >
                {wordCount}
              </div>
              <div
                style={{
                  width: 64,
                  height: 2,
                  background: theme.muted,
                  margin: '6px auto',
                }}
              />
              <div
                style={{
                  fontSize: 30,
                  fontWeight: 700,
                  color: theme.orange,
                  fontFamily: "'JetBrains Mono', monospace",
                }}
              >
                {totalTokens}
              </div>
            </div>
            <div style={{ fontSize: 26, color: theme.dim }}>=</div>
            <div
              style={{
                fontSize: 34,
                fontWeight: 800,
                color: theme.text,
                fontFamily: "'JetBrains Mono', monospace",
                transition: 'all 0.3s',
              }}
            >
              {rounded.toFixed(4)}
            </div>
          </div>

          {/* Probability bar */}
          <div
            style={{
              marginTop: 16,
              height: 8,
              background: theme.card,
              borderRadius: 4,
              overflow: 'hidden',
            }}
          >
            <div
              style={{
                height: '100%',
                width: (probability * 100) + '%',
                background: theme.blue,
                borderRadius: 4,
                transition: 'width 0.3s ease',
              }}
            />
          </div>
        </div>

        {/* Distribution */}
        <div
          style={{
            background: theme.surface,
            borderRadius: 12,
            padding: 14,
            marginBottom: 12,
            border: '1px solid ' + theme.border,
          }}
        >
          <div
            style={{
              fontSize: 11,
              color: theme.dim,
              marginBottom: 10,
              fontWeight: 600,
              letterSpacing: 0.5,
            }}
          >
            PROBABILITY DISTRIBUTION
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
            {wordFreqs.map(([word, count]) => {
              var isSel = word === selectedWord;
              var prob = count / totalTokens;
              return (
                <button
                  key={word}
                  onClick={() => setSelectedWord(word)}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 8,
                    background: isSel ? theme.blue + '0c' : 'transparent',
                    border: 'none',
                    cursor: 'pointer',
                    padding: '4px 6px',
                    borderRadius: 5,
                    transition: 'all 0.2s',
                  }}
                >
                  <div
                    style={{
                      width: 52,
                      fontSize: 11,
                      fontFamily: "'JetBrains Mono', monospace",
                      color: isSel ? theme.blue : theme.dim,
                      fontWeight: isSel ? 700 : 400,
                      textAlign: 'right',
                      flexShrink: 0,
                      transition: 'color 0.2s',
                    }}
                  >
                    {word}
                  </div>
                  <div
                    style={{
                      flex: 1,
                      height: 18,
                      background: theme.card,
                      borderRadius: 3,
                      overflow: 'hidden',
                      position: 'relative',
                    }}
                  >
                    <div
                      style={{
                        height: '100%',
                        width: ((count / maxCount) * 100) + '%',
                        background: isSel ? theme.blue : theme.dim + '40',
                        borderRadius: 3,
                        transition: 'all 0.3s ease',
                      }}
                    />
                    <div
                      style={{
                        position: 'absolute',
                        left: 6,
                        top: '50%',
                        transform: 'translateY(-50%)',
                        fontSize: 10,
                        fontFamily: "'JetBrains Mono', monospace",
                        color: isSel ? theme.text : theme.muted,
                        fontWeight: isSel ? 600 : 400,
                      }}
                    >
                      {count}x
                    </div>
                  </div>
                  <div
                    style={{
                      width: 52,
                      fontSize: 11,
                      fontFamily: "'JetBrains Mono', monospace",
                      color: isSel ? theme.text : theme.dim,
                      textAlign: 'right',
                      flexShrink: 0,
                      fontWeight: isSel ? 600 : 400,
                      transition: 'color 0.2s',
                    }}
                  >
                    {prob.toFixed(4)}
                  </div>
                </button>
              );
            })}
          </div>
        </div>

        {/* Insight */}
        <div
          style={{
            background: theme.blue + '10',
            border: '1px solid ' + theme.blue + '30',
            borderRadius: 10,
            padding: 12,
            fontSize: 12,
            color: theme.muted,
            lineHeight: 1.7,
          }}
        >
          {isSpecial(selectedWord) ? (
            <span>
              <span style={{ color: theme.orange, fontWeight: 700 }}>
                Key insight:{' '}
              </span>
              Special tokens like{' '}
              <span style={{ color: theme.purple, fontWeight: 600 }}>
                "{selectedWord}"
              </span>{' '}
              are counted as regular tokens! They appear{' '}
              <span style={{ color: theme.green, fontWeight: 700 }}>
                {wordCount} time{wordCount !== 1 ? 's' : ''}
              </span>{' '}
              and contribute to the total of{' '}
              <span style={{ color: theme.orange, fontWeight: 700 }}>
                {totalTokens}
              </span>
              . This affects every word's probability in the corpus.
            </span>
          ) : wordCount === 1 ? (
            <span>
              <span style={{ color: theme.blue, fontWeight: 600 }}>
                "{selectedWord}"
              </span>{' '}
              appears only{' '}
              <span style={{ color: theme.green, fontWeight: 700 }}>once</span> in{' '}
              <span style={{ color: theme.orange, fontWeight: 700 }}>
                {totalTokens}
              </span>{' '}
              tokens, giving it a low probability. In real corpora, rare words often
              get near-zero probabilities - a problem solved by smoothing techniques.
            </span>
          ) : (
            <span>
              <span style={{ color: theme.blue, fontWeight: 600 }}>
                "{selectedWord}"
              </span>{' '}
              appears{' '}
              <span style={{ color: theme.green, fontWeight: 700 }}>
                {wordCount} times
              </span>{' '}
              out of{' '}
              <span style={{ color: theme.orange, fontWeight: 700 }}>
                {totalTokens}
              </span>{' '}
              total tokens.
              {wordCount >= maxCount
                ? ' This is among the most frequent tokens in the corpus!'
                : ' More frequent words naturally get higher unigram probability.'}
            </span>
          )}
        </div>
      </div>
    </div>
  );
}

